import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import API from '../services/axios';

function EventDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tickets, setTickets] = useState(1);
  const [booking, setBooking] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => { fetchEvent(); }, [id]);

  const fetchEvent = async () => {
    try {
      const res = await API.get(`/events/${id}`);
      setEvent(res.data.event);
    } catch {
      setError('Event not found');
    } finally {
      setLoading(false);
    }
  };

  const handleBook = async () => {
    setError('');
    setBooking(true);
    try {
      await API.post('/bookings', { eventId: id, numberOfTickets: tickets });
      setSuccess('🎉 Booking successful! Redirecting to your bookings...');
      setTimeout(() => navigate('/my-bookings'), 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Booking failed');
    } finally {
      setBooking(false);
    }
  };

  if (loading) return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="text-center"><div className="text-5xl mb-4 animate-bounce">🎉</div>
        <p className="text-gray-500">Loading event...</p></div>
    </div>
  );

  if (!event) return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="text-center">
        <div className="text-6xl mb-4">😕</div>
        <h2 className="text-2xl font-bold text-gray-700">Event Not Found</h2>
        <button onClick={() => navigate('/home')} className="mt-4 bg-blue-600 text-white px-6 py-2 rounded-lg">Go Home</button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50">

      {/* Hero Image */}
      <div className="relative h-80 md:h-96">
        <img src={event.image || 'https://via.placeholder.com/1200x400?text=Event'}
          alt={event.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
        <div className="absolute bottom-6 left-6 text-white">
          <span className="bg-blue-500 text-xs font-bold px-3 py-1 rounded-full mb-2 inline-block">{event.category}</span>
          <h1 className="text-4xl font-bold">{event.name}</h1>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-4 py-10 grid md:grid-cols-3 gap-8">

        {/* Event Info */}
        <div className="md:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4">About This Event</h2>
            <p className="text-gray-600 leading-relaxed">{event.description}</p>
          </div>

          <div className="bg-white rounded-2xl shadow-sm p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Event Details</h2>
            <div className="grid grid-cols-2 gap-4">
              {[
                { icon: '📅', label: 'Date', value: new Date(event.date).toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }) },
                { icon: '🕐', label: 'Time', value: event.time },
                { icon: '📍', label: 'Venue', value: event.venue },
                { icon: '🎭', label: 'Category', value: event.category },
                { icon: '🎫', label: 'Available Seats', value: `${event.availableSeats} / ${event.totalSeats}` },
                { icon: '📊', label: 'Status', value: event.status.toUpperCase() },
              ].map(item => (
                <div key={item.label} className="flex items-start gap-3 p-3 bg-gray-50 rounded-xl">
                  <span className="text-2xl">{item.icon}</span>
                  <div>
                    <p className="text-xs text-gray-400 font-medium">{item.label}</p>
                    <p className="text-gray-800 font-semibold text-sm">{item.value}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Booking Card */}
        <div className="md:col-span-1">
          <div className="bg-white rounded-2xl shadow-sm p-6 sticky top-24">
            <h2 className="text-xl font-bold text-gray-800 mb-2">Book Tickets</h2>
            <p className="text-3xl font-bold text-blue-600 mb-6">₹{event.price} <span className="text-sm text-gray-400 font-normal">per ticket</span></p>

            {error && <div className="bg-red-50 text-red-700 px-4 py-3 rounded-xl mb-4 text-sm">⚠️ {error}</div>}
            {success && <div className="bg-green-50 text-green-700 px-4 py-3 rounded-xl mb-4 text-sm">{success}</div>}

            {event.availableSeats > 0 && event.status === 'upcoming' ? (
              <>
                <div className="mb-4">
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Number of Tickets</label>
                  <div className="flex items-center gap-3">
                    <button onClick={() => setTickets(Math.max(1, tickets - 1))}
                      className="w-10 h-10 rounded-full bg-gray-100 hover:bg-gray-200 font-bold text-lg transition">−</button>
                    <span className="text-2xl font-bold w-8 text-center">{tickets}</span>
                    <button onClick={() => setTickets(Math.min(event.availableSeats, tickets + 1))}
                      className="w-10 h-10 rounded-full bg-gray-100 hover:bg-gray-200 font-bold text-lg transition">+</button>
                  </div>
                </div>

                <div className="bg-gray-50 rounded-xl p-4 mb-4">
                  <div className="flex justify-between text-sm text-gray-600 mb-2">
                    <span>₹{event.price} × {tickets} ticket(s)</span>
                    <span>₹{event.price * tickets}</span>
                  </div>
                  <div className="flex justify-between font-bold text-gray-800 border-t pt-2">
                    <span>Total</span>
                    <span className="text-blue-600">₹{event.price * tickets}</span>
                  </div>
                </div>

                <button onClick={handleBook} disabled={booking}
                  className="w-full bg-gradient-to-r from-blue-600 to-purple-600 text-white py-3 rounded-xl font-semibold hover:shadow-lg transition disabled:opacity-50">
                  {booking ? '⏳ Booking...' : '🎟️ Book Now'}
                </button>
              </>
            ) : (
              <div className="text-center py-6">
                <div className="text-4xl mb-2">😔</div>
                <p className="text-gray-500 font-medium">
                  {event.availableSeats === 0 ? 'This event is sold out' : 'This event is not available for booking'}
                </p>
              </div>
            )}

            <p className="text-xs text-gray-400 text-center mt-4">Organized by {event.organiser?.name}</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EventDetails;
